import React, { useState, useEffect } from 'react';
import api from './api'; // Adjust the path to your axios instance

const ProductDashboard = () => {
  const [products, setProducts] = useState([]);
  const [searchText, setSearchText] = useState('');
  const [status, setStatus] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Function to call the POST /products/filter endpoint
  const handleSearch = async () => {
    setIsLoading(true);
    try {
      const response = await api.post('/products/filter', {
        search_text: searchText.trim() || null,
        status: status || null
      });
      setProducts(response.data);
    } catch (error) {
      console.error("Failed to fetch filtered products:", error);
    } finally {
      setIsLoading(false);
    }
  };

  // Load all products on component mount
  useEffect(() => {
    handleSearch();
  }, []);

  return (
    <div style={{ padding: '20px' }}>
      <h2>Product Management</h2>

      {/* Filter Section */}
      <div style={{ marginBottom: '20px', display: 'flex', gap: '10px', alignItems: 'center' }}>
        <input
          type="text"
          placeholder="Search by text..."
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          style={{ padding: '8px', width: '200px' }}
        />

        <select 
          value={status} 
          onChange={(e) => setStatus(e.target.value)}
          style={{ padding: '8px' }}
        >
          <option value="">All Statuses</option>
          <option value="ordered">Ordered</option>
          <option value="shipped">Shipped</option>
          <option value="delivered">Delivered</option>
        </select>

        <button 
          onClick={handleSearch} 
          disabled={isLoading}
          style={{ padding: '8px 16px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
        >
          {isLoading ? 'Searching...' : 'Search'}
        </button>
      </div>

      {/* Results Table */}
      <div className="product-list">
        {products.length > 0 ? (
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ backgroundColor: '#f8f9fa', textAlign: 'left' }}>
                <th style={{ padding: '12px', borderBottom: '2px solid #dee2e6' }}>Name</th>
                <th style={{ padding: '12px', borderBottom: '2px solid #dee2e6' }}>Status</th>
                <th style={{ padding: '12px', borderBottom: '2px solid #dee2e6' }}>Price</th>
              </tr>
            </thead>
            <tbody>
              {products.map(p => (
                <tr key={p.id}>
                  <td style={{ padding: '12px', borderBottom: '1px solid #dee2e6' }}>{p.name}</td>
                  <td style={{ padding: '12px', borderBottom: '1px solid #dee2e6' }}>
                    <span style={{ padding: '4px 8px', borderRadius: '12px', fontSize: '12px', textTransform: 'uppercase', backgroundColor: '#e9ecef' }}>
                      {p.status}
                    </span>
                  </td>
                  <td style={{ padding: '12px', borderBottom: '1px solid #dee2e6' }}>${p.price.toFixed(2)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          !isLoading && <p>No products found matching your criteria.</p>
        )}
      </div>
    </div>
  );
};

export default ProductDashboard;
